#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int **disks = (int **)malloc(N * sizeof(int *));
    for (int i = 0; i < N; i++) {
        disks[i] = (int *)malloc(N * sizeof(int));
        disks[i][i] = 1;
    }
    for (int q = 0; q < Q; q++) {
        int type, x, y, k;
        scanf("%d %d %d", &type, &x, &y);
        x--;
        if (type == 1) {
            int count = 0;
            for (int i = 0; i < N; i++) {
                if (disks[x][i] == 0) count++;
            }
            printf("%d\n", count);
        } else {
            scanf("%d", &k);
            k--;
            int file = -1;
            for (int i = 0; i < N; i++) {
                if (disks[x][i] == 1) {
                    if (k == 0) {
                        file = i + 1;
                        break;
                    }
                    k--;
                }
            }
            printf("%d\n", file);
        }
        // simulate the process for the next hour
        for (int i = 0; i < N; i++) {
            int *new_disk = (int *)malloc(N * sizeof(int));
            memset(new_disk, 0, N * sizeof(int));
            for (int j = i; j < N; j++) {
                for (int file = 0; file < N; file++) {
                    if (disks[j][file] == 1) new_disk[file] ^= 1;
                }
            }
            free(disks[i]);
            disks[i] = new_disk;
        }
    }
    for (int i = 0; i < N; i++) free(disks[i]);
    free(disks);
    return 0;
}

